  // ─── TRANSLATION ENGINE ─────────────────────────────────
  String _t(String key) {
        final direct = _translations[_lang]?[key] ?? _translations['en']?[key];
        if (direct != null) return direct;

        // Backward-compatible aliases for renamed registration keys
        const aliases = <String, String>{
            'register_step_of_total': 'registration_step_of_total',
            'registration_step_of_total': 'register_step_of_total',
        };

        final aliasKey = aliases[key];
        if (aliasKey != null) {
            final aliased =
                    _translations[_lang]?[aliasKey] ?? _translations['en']?[aliasKey];
            if (aliased != null) return aliased;
        }

        return key;
  }

  static final Map<String, Map<String, String>> _translations = {
